mapper.select:
SELECT 
FROM verification_code
WHERE target = #{target}
  AND code = #{code}
  AND type = #{type}
  AND used = 0
  AND expire_time > NOW()
ORDER BY create_time DESC
LIMIT 1

mapper.update:
UPDATE verification_code
SET used = 1
WHERE id = #{id}

